-- calc_role_assignments_name
-- Field: RoleAssignments.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_role_assignments_name(p_role_assignment_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(role, '') FROM role_assignments WHERE role_assignment_id = p_role_assignment_id), ' @ ', (SELECT valid_from::timestamptz FROM role_assignments WHERE role_assignment_id = p_role_assignment_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_is_current
-- Field: RoleAssignments.IsCurrent
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_role_assignments_is_current(p_role_assignment_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT valid_from::timestamptz FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) <= calc_role_assignments_as_of_instant(p_role_assignment_id) AND ((SELECT valid_to::timestamptz FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) IS NULL OR (SELECT valid_to::timestamptz FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) > calc_role_assignments_as_of_instant(p_role_assignment_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_current_agent_key
-- Field: RoleAssignments.CurrentAgentKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_role_assignments_current_agent_key(p_role_assignment_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_role_assignments_is_current(p_role_assignment_id) THEN ((SELECT NULLIF(agent, '') FROM role_assignments WHERE role_assignment_id = p_role_assignment_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_is_currently_valid
-- Field: RoleAssignments.IsCurrentlyValid
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_role_assignments_is_currently_valid(p_role_assignment_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(status, '') FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) = 'Active' AND ((SELECT valid_to::timestamptz FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) IS NULL OR (SELECT valid_to::timestamptz FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) > CURRENT_TIMESTAMP)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_agent_role_key
-- Field: RoleAssignments.AgentRoleKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_role_assignments_agent_role_key(p_role_assignment_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_role_assignments_is_currently_valid(p_role_assignment_id) THEN (CONCAT((SELECT NULLIF(agent, '') FROM role_assignments WHERE role_assignment_id = p_role_assignment_id), '|', (SELECT NULLIF(role, '') FROM role_assignments WHERE role_assignment_id = p_role_assignment_id)))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_has_departed
-- Field: RoleAssignments.HasDeparted
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_role_assignments_has_departed(p_role_assignment_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT valid_to::timestamptz FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) IS NOT NULL AND (SELECT valid_to::timestamptz FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) <= CURRENT_TIMESTAMP))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_covers_now
-- Field: RoleAssignments.CoversNow
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_role_assignments_covers_now(p_role_assignment_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(status, '') FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) = 'Active' AND (SELECT valid_from::timestamptz FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) <= CURRENT_TIMESTAMP AND ((SELECT valid_to::timestamptz FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) IS NULL OR (SELECT valid_to::timestamptz FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) > CURRENT_TIMESTAMP)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_role_when_covering
-- Field: RoleAssignments.RoleWhenCovering
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_role_assignments_role_when_covering(p_role_assignment_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_role_assignments_covers_now(p_role_assignment_id) THEN ((SELECT NULLIF(role, '') FROM role_assignments WHERE role_assignment_id = p_role_assignment_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_is_non_human_assignment
-- Field: RoleAssignments.IsNonHumanAssignment
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_role_assignments_is_non_human_assignment(p_role_assignment_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (NOT (calc_role_assignments_agent_kind(p_role_assignment_id) = 'Human'))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_is_human_to_non_human_handover
-- Field: RoleAssignments.IsHumanToNonHumanHandover
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_role_assignments_is_human_to_non_human_handover(p_role_assignment_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_role_assignments_predecessor_agent_kind(p_role_assignment_id) = 'Human' AND calc_role_assignments_is_non_human_assignment(p_role_assignment_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_is_unauthorized_non_human_assignment
-- Field: RoleAssignments.IsUnauthorizedNonHumanAssignment
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_role_assignments_is_unauthorized_non_human_assignment(p_role_assignment_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_role_assignments_is_non_human_assignment(p_role_assignment_id) AND ((SELECT NULLIF(approving_authority_role, '') FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) IS NULL OR (SELECT NULLIF(authorizing_change_request, '') FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) IS NULL)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_decision_count
-- Field: RoleAssignments.DecisionCount
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_role_assignments_decision_count(p_role_assignment_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COUNT(*) FROM agent_decision_records WHERE calc_agent_decision_records_role_assignment_when_scored(agent_decision_record_id) = (SELECT NULLIF(role_assignment_id, '') FROM role_assignments WHERE role_assignment_id = p_role_assignment_id)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_overridden_decision_count
-- Field: RoleAssignments.OverriddenDecisionCount
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_role_assignments_overridden_decision_count(p_role_assignment_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COUNT(*) FROM agent_decision_records WHERE calc_agent_decision_records_role_assignment_when_overridden(agent_decision_record_id) = (SELECT NULLIF(role_assignment_id, '') FROM role_assignments WHERE role_assignment_id = p_role_assignment_id)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_override_rate_percent
-- Field: RoleAssignments.OverrideRatePercent
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_role_assignments_override_rate_percent(p_role_assignment_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN (calc_role_assignments_decision_count(p_role_assignment_id))::NUMERIC = 0 THEN (0)::text ELSE ((COALESCE(CASE WHEN ((COALESCE(CASE WHEN (calc_role_assignments_overridden_decision_count(p_role_assignment_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_role_assignments_overridden_decision_count(p_role_assignment_id))::numeric ELSE NULL END, 0) * COALESCE(100, 0)))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((COALESCE(CASE WHEN (calc_role_assignments_overridden_decision_count(p_role_assignment_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_role_assignments_overridden_decision_count(p_role_assignment_id))::numeric ELSE NULL END, 0) * COALESCE(100, 0)))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN (calc_role_assignments_decision_count(p_role_assignment_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_role_assignments_decision_count(p_role_assignment_id))::numeric ELSE NULL END, 0), 0)))::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_quality_regressed_vs_predecessor
-- Field: RoleAssignments.QualityRegressedVsPredecessor
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_role_assignments_quality_regressed_vs_predecessor(p_role_assignment_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(supersedes_assignment, '') FROM role_assignments WHERE role_assignment_id = p_role_assignment_id) IS NOT NULL AND calc_role_assignments_override_rate_percent(p_role_assignment_id) > calc_role_assignments_predecessor_override_rate_percent(p_role_assignment_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_role_assignments_departed_role_key
-- Field: RoleAssignments.DepartedRoleKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_role_assignments_departed_role_key(p_role_assignment_id TEXT)
