  SELECT (CASE WHEN calc_role_assignments_has_departed(p_role_assignment_id) THEN ((SELECT NULLIF(role, '') FROM role_assignments WHERE role_assignment_id = p_role_assignment_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

