  SELECT ((SELECT NULLIF(title, '') FROM procedure_versions WHERE procedure_version_id = p_procedure_version_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_procedure_versions_count_of_steps
-- Field: ProcedureVersions.CountOfSteps
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_procedure_versions_count_of_steps(p_procedure_version_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM steps WHERE procedure_version = (SELECT NULLIF(procedure_version_id, '') FROM procedure_versions WHERE procedure_version_id = p_procedure_version_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_procedure_versions_count_of_open_knowledge_gaps
-- Field: ProcedureVersions.CountOfOpenKnowledgeGaps
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_procedure_versions_count_of_open_knowledge_gaps(p_procedure_version_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM knowledge_gaps WHERE procedure_version = (SELECT NULLIF(procedure_version_id, '') FROM procedure_versions WHERE procedure_version_id = p_procedure_version_id) AND status = 'Open'))::integer;
$$ LANGUAGE sql STABLE;

-- calc_procedure_versions_is_ready_for_execution
-- Field: ProcedureVersions.IsReadyForExecution
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_procedure_versions_is_ready_for_execution(p_procedure_version_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(status, '') FROM procedure_versions WHERE procedure_version_id = p_procedure_version_id) = 'Approved' AND (calc_procedure_versions_count_of_steps(p_procedure_version_id))::NUMERIC > 0 AND (calc_procedure_versions_count_of_open_knowledge_gaps(p_procedure_version_id))::NUMERIC = 0));
$$ LANGUAGE sql STABLE;

-- calc_procedure_versions_specified_step_count
-- Field: ProcedureVersions.SpecifiedStepCount
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_procedure_versions_specified_step_count(p_procedure_version_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COUNT(*) FROM steps WHERE procedure_version = (SELECT NULLIF(procedure_version_id, '') FROM procedure_versions WHERE procedure_version_id = p_procedure_version_id)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_procedure_versions_overdue_review_count
