-- calc_explanations_name
-- Field: Explanations.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_explanations_name(p_explanation_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(title, '') FROM explanations WHERE explanation_id = p_explanation_id))::text;
$$ LANGUAGE sql STABLE;

