  SELECT (CONCAT((SELECT NULLIF(procedure_execution, '') FROM step_executions WHERE step_execution_id = p_step_execution_id), ' / ', (SELECT NULLIF(step, '') FROM step_executions WHERE step_execution_id = p_step_execution_id)))::text;
