RETURNS BOOLEAN AS $$
  SELECT ((calc_step_executions_was_executed_by_software(p_step_execution_id) AND NOT (calc_step_executions_step_is_software_assigned(p_step_execution_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_step_executions_is_verified
