-- calc_stewardship_assignments_name
-- Field: StewardshipAssignments.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_stewardship_assignments_name(p_stewardship_assignment_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(procedure_version, '') FROM stewardship_assignments WHERE stewardship_assignment_id = p_stewardship_assignment_id), ' / steward=', (SELECT NULLIF(steward_role, '') FROM stewardship_assignments WHERE stewardship_assignment_id = p_stewardship_assignment_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_stewardship_assignments_count_of_review_events
-- Field: StewardshipAssignments.CountOfReviewEvents
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_stewardship_assignments_count_of_review_events(p_stewardship_assignment_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM review_events WHERE procedure_version = (SELECT NULLIF(procedure_version, '') FROM stewardship_assignments WHERE stewardship_assignment_id = p_stewardship_assignment_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_stewardship_assignments_has_ever_been_reviewed
-- Field: StewardshipAssignments.HasEverBeenReviewed
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_stewardship_assignments_has_ever_been_reviewed(p_stewardship_assignment_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_stewardship_assignments_count_of_review_events(p_stewardship_assignment_id))::NUMERIC > 0)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_stewardship_assignments_is_current_assignment
-- Field: StewardshipAssignments.IsCurrentAssignment
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_stewardship_assignments_is_current_assignment(p_stewardship_assignment_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT valid_from::timestamptz FROM stewardship_assignments WHERE stewardship_assignment_id = p_stewardship_assignment_id) <= CURRENT_TIMESTAMP AND ((SELECT valid_to::timestamptz FROM stewardship_assignments WHERE stewardship_assignment_id = p_stewardship_assignment_id) IS NULL OR (SELECT valid_to::timestamptz FROM stewardship_assignments WHERE stewardship_assignment_id = p_stewardship_assignment_id) > CURRENT_TIMESTAMP)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_authority_agent
-- Field: ChangeRequests.AuthorityAgent
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: CurrentAgent from related Roles


CREATE OR REPLACE FUNCTION calc_change_requests_authority_agent(p_change_request_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT current_agent::text FROM roles WHERE role_id = (SELECT authority_role FROM change_requests WHERE change_request_id = p_change_request_id));
$$ LANGUAGE sql STABLE;

-- calc_change_requests_authority_role_label
-- Field: ChangeRequests.AuthorityRoleLabel
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: Label from related Roles


CREATE OR REPLACE FUNCTION calc_change_requests_authority_role_label(p_change_request_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT label::text FROM roles WHERE role_id = (SELECT authority_role FROM change_requests WHERE change_request_id = p_change_request_id));
$$ LANGUAGE sql STABLE;

-- calc_change_requests_touches_live_version
-- Field: ChangeRequests.TouchesLiveVersion
-- Type: lookup | DataType: boolean | Returns: BOOLEAN
-- Lookup: IsLive from related ProcedureVersions


CREATE OR REPLACE FUNCTION calc_change_requests_touches_live_version(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT calc_procedure_versions_is_live((SELECT procedure_version FROM change_requests WHERE change_request_id = p_change_request_id));
$$ LANGUAGE sql STABLE;

-- calc_change_requests_name
-- Field: ChangeRequests.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_change_requests_name(p_change_request_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(title, '') FROM change_requests WHERE change_request_id = p_change_request_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_is_open
-- Field: ChangeRequests.IsOpen
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_is_open(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((((SELECT NULLIF(status, '') FROM change_requests WHERE change_request_id = p_change_request_id) = 'Draft' OR (SELECT NULLIF(status, '') FROM change_requests WHERE change_request_id = p_change_request_id) = 'UnderReview' OR (SELECT NULLIF(status, '') FROM change_requests WHERE change_request_id = p_change_request_id) = 'Approved') AND (SELECT implemented_at::timestamptz FROM change_requests WHERE change_request_id = p_change_request_id) IS NULL))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_open_change_version_key
-- Field: ChangeRequests.OpenChangeVersionKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_change_requests_open_change_version_key(p_change_request_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_change_requests_is_open(p_change_request_id) THEN ((SELECT NULLIF(procedure_version, '') FROM change_requests WHERE change_request_id = p_change_request_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_is_decided
-- Field: ChangeRequests.IsDecided
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_is_decided(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT decided_at::timestamptz FROM change_requests WHERE change_request_id = p_change_request_id) IS NOT NULL)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_days_pending
-- Field: ChangeRequests.DaysPending
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_change_requests_days_pending(p_change_request_id TEXT)
RETURNS INTEGER AS $$
  SELECT (CASE WHEN calc_change_requests_is_decided(p_change_request_id) THEN (((SELECT decided_at::timestamptz FROM change_requests WHERE change_request_id = p_change_request_id)::date - (SELECT requested_at::timestamptz FROM change_requests WHERE change_request_id = p_change_request_id)::date))::text ELSE ((CURRENT_TIMESTAMP::date - (SELECT requested_at::timestamptz FROM change_requests WHERE change_request_id = p_change_request_id)::date))::text END)::integer;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_is_still_pending
-- Field: ChangeRequests.IsStillPending
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_is_still_pending(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_change_requests_is_open(p_change_request_id) AND NOT (calc_change_requests_is_decided(p_change_request_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_is_stalled
-- Field: ChangeRequests.IsStalled
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_is_stalled(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_change_requests_is_still_pending(p_change_request_id) AND (calc_change_requests_days_pending(p_change_request_id))::NUMERIC > 14));
$$ LANGUAGE sql STABLE;

-- calc_change_requests_requester_is_authority
-- Field: ChangeRequests.RequesterIsAuthority
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_requester_is_authority(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT NULLIF(requested_by_agent, '') FROM change_requests WHERE change_request_id = p_change_request_id) = calc_change_requests_authority_agent(p_change_request_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_awaits_authority_decision
-- Field: ChangeRequests.AwaitsAuthorityDecision
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_awaits_authority_decision(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(status, '') FROM change_requests WHERE change_request_id = p_change_request_id) = 'UnderReview' AND NOT (calc_change_requests_is_decided(p_change_request_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_is_live_decision_backlog
-- Field: ChangeRequests.IsLiveDecisionBacklog
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_is_live_decision_backlog(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_change_requests_awaits_authority_decision(p_change_request_id) AND calc_change_requests_touches_live_version(p_change_request_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_blocks_an_open_gap
-- Field: ChangeRequests.BlocksAnOpenGap
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_blocks_an_open_gap(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_change_requests_is_live_decision_backlog(p_change_request_id) AND (SELECT NULLIF(change_kind, '') FROM change_requests WHERE change_request_id = p_change_request_id) = 'Enhancement'))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_backlog_version_key
-- Field: ChangeRequests.BacklogVersionKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_change_requests_backlog_version_key(p_change_request_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_change_requests_is_live_decision_backlog(p_change_request_id) THEN ((SELECT NULLIF(procedure_version, '') FROM change_requests WHERE change_request_id = p_change_request_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_is_my_pending_decision
-- Field: ChangeRequests.IsMyPendingDecision
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_is_my_pending_decision(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(authority_role, '') FROM change_requests WHERE change_request_id = p_change_request_id) = 'hr-policy-owner' AND calc_change_requests_awaits_authority_decision(p_change_request_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_is_my_blocking_backlog
-- Field: ChangeRequests.IsMyBlockingBacklog
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_is_my_blocking_backlog(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_change_requests_is_my_pending_decision(p_change_request_id) AND calc_change_requests_blocks_an_open_gap(p_change_request_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_is_my_overdue_backlog
-- Field: ChangeRequests.IsMyOverdueBacklog
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_is_my_overdue_backlog(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_change_requests_is_my_blocking_backlog(p_change_request_id) AND (calc_change_requests_days_pending(p_change_request_id))::NUMERIC > 14));
$$ LANGUAGE sql STABLE;

-- calc_change_requests_is_implemented
-- Field: ChangeRequests.IsImplemented
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_is_implemented(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT implemented_at::timestamptz FROM change_requests WHERE change_request_id = p_change_request_id) IS NOT NULL)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_is_my_decided_request
-- Field: ChangeRequests.IsMyDecidedRequest
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_is_my_decided_request(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(authority_role, '') FROM change_requests WHERE change_request_id = p_change_request_id) = 'hr-policy-owner' AND calc_change_requests_is_decided(p_change_request_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_is_my_decided_but_unlanded
-- Field: ChangeRequests.IsMyDecidedButUnlanded
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_is_my_decided_but_unlanded(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_change_requests_is_my_decided_request(p_change_request_id) AND NOT (calc_change_requests_is_implemented(p_change_request_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_decision_latency_days
-- Field: ChangeRequests.DecisionLatencyDays
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_change_requests_decision_latency_days(p_change_request_id TEXT)
RETURNS INTEGER AS $$
  SELECT (CASE WHEN calc_change_requests_is_decided(p_change_request_id) THEN (((SELECT decided_at::timestamptz FROM change_requests WHERE change_request_id = p_change_request_id)::date - (SELECT requested_at::timestamptz FROM change_requests WHERE change_request_id = p_change_request_id)::date))::text ELSE (0)::text END)::integer;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_implementation_latency_days
-- Field: ChangeRequests.ImplementationLatencyDays
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_change_requests_implementation_latency_days(p_change_request_id TEXT)
RETURNS INTEGER AS $$
  SELECT (CASE WHEN calc_change_requests_is_implemented(p_change_request_id) THEN (((SELECT implemented_at::timestamptz FROM change_requests WHERE change_request_id = p_change_request_id)::date - (SELECT decided_at::timestamptz FROM change_requests WHERE change_request_id = p_change_request_id)::date))::text ELSE (0)::text END)::integer;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_delay_is_downstream_of_me
-- Field: ChangeRequests.DelayIsDownstreamOfMe
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_delay_is_downstream_of_me(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_change_requests_is_my_decided_but_unlanded(p_change_request_id) AND (calc_change_requests_decision_latency_days(p_change_request_id))::NUMERIC <= 14));
$$ LANGUAGE sql STABLE;

-- calc_change_requests_unlanded_version_key
-- Field: ChangeRequests.UnlandedVersionKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_change_requests_unlanded_version_key(p_change_request_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_change_requests_is_my_decided_but_unlanded(p_change_request_id) THEN ((SELECT NULLIF(procedure_version, '') FROM change_requests WHERE change_request_id = p_change_request_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_is_approved_not_implemented
-- Field: ChangeRequests.IsApprovedNotImplemented
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_is_approved_not_implemented(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(status, '') FROM change_requests WHERE change_request_id = p_change_request_id) = 'Approved' AND NOT (calc_change_requests_is_implemented(p_change_request_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_days_since_approval
-- Field: ChangeRequests.DaysSinceApproval
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_change_requests_days_since_approval(p_change_request_id TEXT)
RETURNS INTEGER AS $$
  SELECT (CASE WHEN calc_change_requests_is_decided(p_change_request_id) THEN ((CURRENT_TIMESTAMP::date - (SELECT decided_at::timestamptz FROM change_requests WHERE change_request_id = p_change_request_id)::date))::text ELSE (0)::text END)::integer;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_is_stalled_implementation
-- Field: ChangeRequests.IsStalledImplementation
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_is_stalled_implementation(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_change_requests_is_approved_not_implemented(p_change_request_id) AND (calc_change_requests_days_since_approval(p_change_request_id))::NUMERIC > 14));
$$ LANGUAGE sql STABLE;

-- calc_change_requests_stalled_implementation_version_key
-- Field: ChangeRequests.StalledImplementationVersionKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_change_requests_stalled_implementation_version_key(p_change_request_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_change_requests_is_stalled_implementation(p_change_request_id) THEN ((SELECT NULLIF(procedure_version, '') FROM change_requests WHERE change_request_id = p_change_request_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_approved_version_key
-- Field: ChangeRequests.ApprovedVersionKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_change_requests_approved_version_key(p_change_request_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_change_requests_is_approved_decision(p_change_request_id) THEN ((SELECT NULLIF(procedure_version, '') FROM change_requests WHERE change_request_id = p_change_request_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_change_requests_is_approved_decision
-- Field: ChangeRequests.IsApprovedDecision
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_change_requests_is_approved_decision(p_change_request_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT NULLIF(status, '') FROM change_requests WHERE change_request_id = p_change_request_id) = 'Approved')::boolean;
$$ LANGUAGE sql STABLE;

-- calc_review_events_as_of_instant
-- Field: ReviewEvents.AsOfInstant
-- Type: lookup | DataType: datetime | Returns: TIMESTAMPTZ
-- Lookup: AsOfInstant from related EvaluationContexts


CREATE OR REPLACE FUNCTION calc_review_events_as_of_instant(p_review_event_id TEXT)
RETURNS TIMESTAMPTZ AS $$
  SELECT (SELECT as_of_instant::timestamptz FROM evaluation_contexts WHERE evaluation_context_id = (SELECT evaluation_context FROM review_events WHERE review_event_id = p_review_event_id));
$$ LANGUAGE sql STABLE;

-- calc_review_events_promised_cadence_days
-- Field: ReviewEvents.PromisedCadenceDays
-- Type: lookup | DataType: integer | Returns: NUMERIC
-- Lookup: StewardReviewCadenceDays from related ProcedureVersions


CREATE OR REPLACE FUNCTION calc_review_events_promised_cadence_days(p_review_event_id TEXT)
RETURNS NUMERIC AS $$
  SELECT calc_procedure_versions_steward_review_cadence_days((SELECT procedure_version FROM review_events WHERE review_event_id = p_review_event_id));
$$ LANGUAGE sql STABLE;

-- calc_review_events_name
-- Field: ReviewEvents.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_review_events_name(p_review_event_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(procedure_version, '') FROM review_events WHERE review_event_id = p_review_event_id), ' / ', (SELECT NULLIF(review_kind, '') FROM review_events WHERE review_event_id = p_review_event_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_review_events_is_overdue
-- Field: ReviewEvents.IsOverdue
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_review_events_is_overdue(p_review_event_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT next_review_due::timestamptz FROM review_events WHERE review_event_id = p_review_event_id) < calc_review_events_as_of_instant(p_review_event_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_review_events_overdue_version_key
-- Field: ReviewEvents.OverdueVersionKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_review_events_overdue_version_key(p_review_event_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_review_events_is_overdue(p_review_event_id) THEN ((SELECT NULLIF(procedure_version, '') FROM review_events WHERE review_event_id = p_review_event_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_review_events_days_since_reviewed
-- Field: ReviewEvents.DaysSinceReviewed
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_review_events_days_since_reviewed(p_review_event_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((CURRENT_TIMESTAMP::date - (SELECT reviewed_at::timestamptz FROM review_events WHERE review_event_id = p_review_event_id)::date))::integer;
$$ LANGUAGE sql STABLE;

-- calc_review_events_exceeds_promised_cadence
-- Field: ReviewEvents.ExceedsPromisedCadence
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_review_events_exceeds_promised_cadence(p_review_event_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_review_events_days_since_reviewed(p_review_event_id) > calc_review_events_promised_cadence_days(p_review_event_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_review_events_cadence_drift_days
-- Field: ReviewEvents.CadenceDriftDays
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_review_events_cadence_drift_days(p_review_event_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((COALESCE(CASE WHEN (calc_review_events_days_since_reviewed(p_review_event_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_review_events_days_since_reviewed(p_review_event_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_review_events_promised_cadence_days(p_review_event_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_review_events_promised_cadence_days(p_review_event_id))::numeric ELSE NULL END, 0)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_review_events_promise_and_behavior_disagree
-- Field: ReviewEvents.PromiseAndBehaviorDisagree
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_review_events_promise_and_behavior_disagree(p_review_event_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_review_events_exceeds_promised_cadence(p_review_event_id) AND NOT (calc_review_events_is_overdue(p_review_event_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_review_events_cadence_breach_version_key
-- Field: ReviewEvents.CadenceBreachVersionKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_review_events_cadence_breach_version_key(p_review_event_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_review_events_exceeds_promised_cadence(p_review_event_id) THEN ((SELECT NULLIF(procedure_version, '') FROM review_events WHERE review_event_id = p_review_event_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_learning_activities_name
-- Field: LearningActivities.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_learning_activities_name(p_learning_activity_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(activity_kind, '') FROM learning_activities WHERE learning_activity_id = p_learning_activity_id), ' / ', (SELECT occurred_at::timestamptz FROM learning_activities WHERE learning_activity_id = p_learning_activity_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_operational_bindings_as_of_instant
-- Field: OperationalBindings.AsOfInstant
-- Type: lookup | DataType: datetime | Returns: TIMESTAMPTZ
-- Lookup: AsOfInstant from related EvaluationContexts


CREATE OR REPLACE FUNCTION calc_operational_bindings_as_of_instant(p_operational_binding_id TEXT)
RETURNS TIMESTAMPTZ AS $$
  SELECT (SELECT as_of_instant::timestamptz FROM evaluation_contexts WHERE evaluation_context_id = (SELECT evaluation_context FROM operational_bindings WHERE operational_binding_id = p_operational_binding_id));
$$ LANGUAGE sql STABLE;

-- calc_operational_bindings_resource_is_approved
-- Field: OperationalBindings.ResourceIsApproved
-- Type: lookup | DataType: boolean | Returns: BOOLEAN
-- Lookup: IsApprovedSource from related Resources


CREATE OR REPLACE FUNCTION calc_operational_bindings_resource_is_approved(p_operational_binding_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT calc_resources_is_approved_source((SELECT resource FROM operational_bindings WHERE operational_binding_id = p_operational_binding_id));
$$ LANGUAGE sql STABLE;

-- calc_operational_bindings_name
-- Field: OperationalBindings.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_operational_bindings_name(p_operational_binding_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(step, '') FROM operational_bindings WHERE operational_binding_id = p_operational_binding_id), ' / ', (SELECT NULLIF(record_or_schema_key, '') FROM operational_bindings WHERE operational_binding_id = p_operational_binding_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_operational_bindings_age_minutes
-- Field: OperationalBindings.AgeMinutes
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_operational_bindings_age_minutes(p_operational_binding_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((EXTRACT(EPOCH FROM (calc_operational_bindings_as_of_instant(p_operational_binding_id)::timestamp - (SELECT last_observed_at::timestamptz FROM operational_bindings WHERE operational_binding_id = p_operational_binding_id)::timestamp)) / 60))::integer;
$$ LANGUAGE sql STABLE;

-- calc_operational_bindings_is_fresh
-- Field: OperationalBindings.IsFresh
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_operational_bindings_is_fresh(p_operational_binding_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_operational_bindings_age_minutes(p_operational_binding_id) <= (SELECT freshness_sla_minutes FROM operational_bindings WHERE operational_binding_id = p_operational_binding_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_operational_bindings_stale_binding_step_key
-- Field: OperationalBindings.StaleBindingStepKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_operational_bindings_stale_binding_step_key(p_operational_binding_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN NOT (calc_operational_bindings_is_fresh(p_operational_binding_id)) THEN ((SELECT NULLIF(step, '') FROM operational_bindings WHERE operational_binding_id = p_operational_binding_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_operational_bindings_authoritative_stale_step_key
-- Field: OperationalBindings.AuthoritativeStaleStepKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_operational_bindings_authoritative_stale_step_key(p_operational_binding_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (NOT (calc_operational_bindings_is_fresh(p_operational_binding_id)) AND COALESCE((SELECT is_authoritative FROM operational_bindings WHERE operational_binding_id = p_operational_binding_id), FALSE)) THEN ((SELECT NULLIF(step, '') FROM operational_bindings WHERE operational_binding_id = p_operational_binding_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_operational_bindings_is_stale_and_authoritative
-- Field: OperationalBindings.IsStaleAndAuthoritative
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_operational_bindings_is_stale_and_authoritative(p_operational_binding_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((COALESCE((SELECT is_authoritative FROM operational_bindings WHERE operational_binding_id = p_operational_binding_id), FALSE) AND NOT (calc_operational_bindings_is_fresh(p_operational_binding_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_operational_bindings_step_when_stale
-- Field: OperationalBindings.StepWhenStale
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_operational_bindings_step_when_stale(p_operational_binding_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_operational_bindings_is_stale_and_authoritative(p_operational_binding_id) THEN ((SELECT NULLIF(step, '') FROM operational_bindings WHERE operational_binding_id = p_operational_binding_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_operational_bindings_is_usable_for_drafting
-- Field: OperationalBindings.IsUsableForDrafting
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_operational_bindings_is_usable_for_drafting(p_operational_binding_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_operational_bindings_resource_is_approved(p_operational_binding_id) AND calc_operational_bindings_is_fresh(p_operational_binding_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_operational_bindings_step_when_unusable
-- Field: OperationalBindings.StepWhenUnusable
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_operational_bindings_step_when_unusable(p_operational_binding_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_operational_bindings_is_usable_for_drafting(p_operational_binding_id) THEN ('')::text ELSE ((SELECT NULLIF(step, '') FROM operational_bindings WHERE operational_binding_id = p_operational_binding_id))::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_communication_policies_name
-- Field: CommunicationPolicies.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_communication_policies_name(p_communication_policy_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(channel, '') FROM communication_policies WHERE communication_policy_id = p_communication_policy_id), ' policy / ', (SELECT NULLIF(procedure_version, '') FROM communication_policies WHERE communication_policy_id = p_communication_policy_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_communication_policies_consent_violation_count
-- Field: CommunicationPolicies.ConsentViolationCount
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_communication_policies_consent_violation_count(p_communication_policy_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COUNT(*) FROM message_deliveries WHERE calc_message_deliveries_policy_channel(message_delivery_id) = (SELECT NULLIF(communication_policy_id, '') FROM communication_policies WHERE communication_policy_id = p_communication_policy_id) AND calc_message_deliveries_is_consent_violation(message_delivery_id) = TRUE))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_communication_policies_quiet_hours_violation_count
-- Field: CommunicationPolicies.QuietHoursViolationCount
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_communication_policies_quiet_hours_violation_count(p_communication_policy_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COUNT(*) FROM message_deliveries WHERE calc_message_deliveries_quiet_hours_violation_policy_key(message_delivery_id) = (SELECT NULLIF(communication_policy_id, '') FROM communication_policies WHERE communication_policy_id = p_communication_policy_id)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_communication_policies_is_active_policy
-- Field: CommunicationPolicies.IsActivePolicy
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_communication_policies_is_active_policy(p_communication_policy_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT NULLIF(status, '') FROM communication_policies WHERE communication_policy_id = p_communication_policy_id) = 'Active')::boolean;
$$ LANGUAGE sql STABLE;

-- calc_message_templates_policy_max_message_length
-- Field: MessageTemplates.PolicyMaxMessageLength
-- Type: lookup | DataType: integer | Returns: INTEGER
-- Lookup: MaxMessageLength from related CommunicationPolicies


CREATE OR REPLACE FUNCTION calc_message_templates_policy_max_message_length(p_message_template_id TEXT)
RETURNS INTEGER AS $$
  SELECT (SELECT max_message_length::integer FROM communication_policies WHERE communication_policy_id = (SELECT communication_policy FROM message_templates WHERE message_template_id = p_message_template_id));
$$ LANGUAGE sql STABLE;

-- calc_message_templates_policy_max_segments
-- Field: MessageTemplates.PolicyMaxSegments
-- Type: lookup | DataType: integer | Returns: INTEGER
-- Lookup: MaxSegments from related CommunicationPolicies


CREATE OR REPLACE FUNCTION calc_message_templates_policy_max_segments(p_message_template_id TEXT)
RETURNS INTEGER AS $$
  SELECT (SELECT max_segments::integer FROM communication_policies WHERE communication_policy_id = (SELECT communication_policy FROM message_templates WHERE message_template_id = p_message_template_id));
$$ LANGUAGE sql STABLE;

