-- calc_send_intents_name
-- Field: SendIntents.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_send_intents_name(p_send_intent_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(recipient, '') FROM send_intents WHERE send_intent_id = p_send_intent_id), ' / ', (SELECT NULLIF(message_template, '') FROM send_intents WHERE send_intent_id = p_send_intent_id), ' / intent'))::text;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_consent_gate_passed
-- Field: SendIntents.ConsentGatePassed
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_consent_gate_passed(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((NOT (calc_send_intents_intent_requires_consent(p_send_intent_id)) OR calc_send_intents_recipient_has_channel_consent(p_send_intent_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_reachability_gate_passed
-- Field: SendIntents.ReachabilityGatePassed
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_reachability_gate_passed(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN calc_send_intents_intent_channel(p_send_intent_id) = 'SMS' THEN (calc_send_intents_recipient_is_sms_reachable(p_send_intent_id))::text ELSE (calc_send_intents_recipient_is_email_reachable(p_send_intent_id))::text END)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_permission_gate_passed
-- Field: SendIntents.PermissionGatePassed
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_permission_gate_passed(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_send_intents_policy_is_active(p_send_intent_id) AND (calc_send_intents_consent_gate_passed(p_send_intent_id) AND calc_send_intents_reachability_gate_passed(p_send_intent_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_intent_policy_has_quiet_hours
-- Field: SendIntents.IntentPolicyHasQuietHours
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_intent_policy_has_quiet_hours(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_send_intents_intent_quiet_start_hour(p_send_intent_id) <> calc_send_intents_intent_quiet_end_hour(p_send_intent_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_intent_quiet_window_wraps
-- Field: SendIntents.IntentQuietWindowWraps
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_intent_quiet_window_wraps(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_send_intents_intent_quiet_start_hour(p_send_intent_id) > calc_send_intents_intent_quiet_end_hour(p_send_intent_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_intent_is_inside_quiet_window
-- Field: SendIntents.IntentIsInsideQuietWindow
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_intent_is_inside_quiet_window(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN calc_send_intents_intent_quiet_window_wraps(p_send_intent_id) THEN (((SELECT proposed_send_at_local_hour FROM send_intents WHERE send_intent_id = p_send_intent_id) >= calc_send_intents_intent_quiet_start_hour(p_send_intent_id) OR (SELECT proposed_send_at_local_hour FROM send_intents WHERE send_intent_id = p_send_intent_id) < calc_send_intents_intent_quiet_end_hour(p_send_intent_id)))::text ELSE (((SELECT proposed_send_at_local_hour FROM send_intents WHERE send_intent_id = p_send_intent_id) >= calc_send_intents_intent_quiet_start_hour(p_send_intent_id) AND (SELECT proposed_send_at_local_hour FROM send_intents WHERE send_intent_id = p_send_intent_id) < calc_send_intents_intent_quiet_end_hour(p_send_intent_id)))::text END)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_timing_gate_passed
-- Field: SendIntents.TimingGatePassed
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_timing_gate_passed(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((NOT (calc_send_intents_intent_policy_has_quiet_hours(p_send_intent_id)) OR NOT (calc_send_intents_intent_is_inside_quiet_window(p_send_intent_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_hours_until_window_opens
-- Field: SendIntents.HoursUntilWindowOpens
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_send_intents_hours_until_window_opens(p_send_intent_id TEXT)
RETURNS INTEGER AS $$
  SELECT (CASE WHEN calc_send_intents_timing_gate_passed(p_send_intent_id) THEN (0)::text ELSE (CASE WHEN (SELECT proposed_send_at_local_hour FROM send_intents WHERE send_intent_id = p_send_intent_id) < calc_send_intents_intent_quiet_end_hour(p_send_intent_id) THEN ((COALESCE(CASE WHEN (calc_send_intents_intent_quiet_end_hour(p_send_intent_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_send_intents_intent_quiet_end_hour(p_send_intent_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN ((SELECT proposed_send_at_local_hour FROM send_intents WHERE send_intent_id = p_send_intent_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT proposed_send_at_local_hour FROM send_intents WHERE send_intent_id = p_send_intent_id))::numeric ELSE NULL END, 0)))::text ELSE ((COALESCE(CASE WHEN ((COALESCE(24, 0) - COALESCE(CASE WHEN ((SELECT proposed_send_at_local_hour FROM send_intents WHERE send_intent_id = p_send_intent_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT proposed_send_at_local_hour FROM send_intents WHERE send_intent_id = p_send_intent_id))::numeric ELSE NULL END, 0)))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((COALESCE(24, 0) - COALESCE(CASE WHEN ((SELECT proposed_send_at_local_hour FROM send_intents WHERE send_intent_id = p_send_intent_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT proposed_send_at_local_hour FROM send_intents WHERE send_intent_id = p_send_intent_id))::numeric ELSE NULL END, 0)))::numeric ELSE NULL END, 0) + COALESCE(CASE WHEN (calc_send_intents_intent_quiet_end_hour(p_send_intent_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_send_intents_intent_quiet_end_hour(p_send_intent_id))::numeric ELSE NULL END, 0)))::text END)::text END)::integer;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_length_gate_passed
-- Field: SendIntents.LengthGatePassed
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_length_gate_passed(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((((SELECT proposed_body_length FROM send_intents WHERE send_intent_id = p_send_intent_id))::NUMERIC > 0 AND (SELECT proposed_segment_count FROM send_intents WHERE send_intent_id = p_send_intent_id) <= calc_send_intents_intent_max_segments(p_send_intent_id)));
$$ LANGUAGE sql STABLE;

-- calc_send_intents_opt_out_gate_passed
-- Field: SendIntents.OptOutGatePassed
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_opt_out_gate_passed(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_send_intents_intent_required_opt_out_phrase(p_send_intent_id) IS NULL OR (((SELECT proposed_opt_out_position FROM send_intents WHERE send_intent_id = p_send_intent_id))::NUMERIC > 0 AND (SELECT proposed_opt_out_position FROM send_intents WHERE send_intent_id = p_send_intent_id) <= calc_send_intents_intent_max_message_length(p_send_intent_id))));
$$ LANGUAGE sql STABLE;

-- calc_send_intents_content_gate_passed
-- Field: SendIntents.ContentGatePassed
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_content_gate_passed(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_send_intents_length_gate_passed(p_send_intent_id) AND calc_send_intents_opt_out_gate_passed(p_send_intent_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_approval_is_human
-- Field: SendIntents.ApprovalIsHuman
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_approval_is_human(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_send_intents_approval_role_agent_kind(p_send_intent_id) = 'Human')::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_authorization_gate_passed
-- Field: SendIntents.AuthorizationGatePassed
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_authorization_gate_passed(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_send_intents_template_is_sendable(p_send_intent_id) AND (calc_send_intents_execution_has_legal_clearance(p_send_intent_id) AND calc_send_intents_approval_is_human(p_send_intent_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_is_cleared_to_send
-- Field: SendIntents.IsClearedToSend
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_is_cleared_to_send(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_send_intents_permission_gate_passed(p_send_intent_id) AND (calc_send_intents_timing_gate_passed(p_send_intent_id) AND (calc_send_intents_content_gate_passed(p_send_intent_id) AND calc_send_intents_authorization_gate_passed(p_send_intent_id)))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_blocking_gate_name
-- Field: SendIntents.BlockingGateName
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_send_intents_blocking_gate_name(p_send_intent_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_send_intents_is_cleared_to_send(p_send_intent_id) THEN ('')::text ELSE (CASE WHEN NOT (calc_send_intents_permission_gate_passed(p_send_intent_id)) THEN ('Permission')::text ELSE (CASE WHEN NOT (calc_send_intents_timing_gate_passed(p_send_intent_id)) THEN ('Timing')::text ELSE (CASE WHEN NOT (calc_send_intents_content_gate_passed(p_send_intent_id)) THEN ('Content')::text ELSE ('Authorization')::text END)::text END)::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_has_resulting_delivery
-- Field: SendIntents.HasResultingDelivery
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_has_resulting_delivery(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT NULLIF(resulting_delivery, '') FROM send_intents WHERE send_intent_id = p_send_intent_id) IS NOT NULL)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_is_overridden_refusal
-- Field: SendIntents.IsOverriddenRefusal
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_is_overridden_refusal(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((NOT (calc_send_intents_is_cleared_to_send(p_send_intent_id)) AND (calc_send_intents_has_resulting_delivery(p_send_intent_id) AND calc_send_intents_resulting_delivery_was_transmitted(p_send_intent_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_is_silently_dropped
-- Field: SendIntents.IsSilentlyDropped
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_is_silently_dropped(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((NOT (calc_send_intents_is_cleared_to_send(p_send_intent_id)) AND NOT (calc_send_intents_has_resulting_delivery(p_send_intent_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_refusal_cited_an_exception
-- Field: SendIntents.RefusalCitedAnException
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_refusal_cited_an_exception(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_send_intents_resulting_delivery_exception(p_send_intent_id) IS NOT NULL)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_is_properly_handled_refusal
-- Field: SendIntents.IsProperlyHandledRefusal
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_send_intents_is_properly_handled_refusal(p_send_intent_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((NOT (calc_send_intents_is_cleared_to_send(p_send_intent_id)) AND (calc_send_intents_has_resulting_delivery(p_send_intent_id) AND (NOT (calc_send_intents_resulting_delivery_was_transmitted(p_send_intent_id)) AND calc_send_intents_refusal_cited_an_exception(p_send_intent_id)))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_send_intents_refusal_failure_execution_key
-- Field: SendIntents.RefusalFailureExecutionKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_send_intents_refusal_failure_execution_key(p_send_intent_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_send_intents_is_overridden_refusal(p_send_intent_id) OR calc_send_intents_is_silently_dropped(p_send_intent_id)) THEN ((SELECT NULLIF(procedure_execution, '') FROM send_intents WHERE send_intent_id = p_send_intent_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_deciding_agent_kind
-- Field: AgentDecisionRecords.DecidingAgentKind
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: AgentKind from related Agents


CREATE OR REPLACE FUNCTION calc_agent_decision_records_deciding_agent_kind(p_agent_decision_record_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT agent_kind::text FROM agents WHERE agent_id = (SELECT deciding_agent FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id));
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_step_of_decision
-- Field: AgentDecisionRecords.StepOfDecision
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: Step from related StepExecutions


CREATE OR REPLACE FUNCTION calc_agent_decision_records_step_of_decision(p_agent_decision_record_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT step::text FROM step_executions WHERE step_execution_id = (SELECT step_execution FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id));
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_reviewer_agent_kind
-- Field: AgentDecisionRecords.ReviewerAgentKind
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: AgentKind from related Agents


CREATE OR REPLACE FUNCTION calc_agent_decision_records_reviewer_agent_kind(p_agent_decision_record_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT agent_kind::text FROM agents WHERE agent_id = (SELECT reviewed_by_agent FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id));
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_name
-- Field: AgentDecisionRecords.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_agent_decision_records_name(p_agent_decision_record_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(deciding_agent, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id), ': ', LEFT(((SELECT NULLIF(decision_summary, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id))::text, (60)::integer)))::text;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_was_overridden
-- Field: AgentDecisionRecords.WasOverridden
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_agent_decision_records_was_overridden(p_agent_decision_record_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(human_disposition, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id) = 'Corrected' OR (SELECT NULLIF(human_disposition, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id) = 'Reversed'))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_was_reviewed
-- Field: AgentDecisionRecords.WasReviewed
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_agent_decision_records_was_reviewed(p_agent_decision_record_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(human_disposition, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id) IS NOT NULL AND (SELECT NULLIF(human_disposition, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id) <> 'NotReviewed'))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_deciding_agent_when_overridden
-- Field: AgentDecisionRecords.DecidingAgentWhenOverridden
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_agent_decision_records_deciding_agent_when_overridden(p_agent_decision_record_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_agent_decision_records_was_overridden(p_agent_decision_record_id) THEN ((SELECT NULLIF(deciding_agent, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_role_assignment_when_scored
-- Field: AgentDecisionRecords.RoleAssignmentWhenScored
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_agent_decision_records_role_assignment_when_scored(p_agent_decision_record_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (SELECT NULLIF(under_role_assignment, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id) IS NOT NULL THEN ((SELECT NULLIF(under_role_assignment, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_role_assignment_when_overridden
-- Field: AgentDecisionRecords.RoleAssignmentWhenOverridden
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_agent_decision_records_role_assignment_when_overridden(p_agent_decision_record_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_agent_decision_records_was_overridden(p_agent_decision_record_id) THEN ((SELECT NULLIF(under_role_assignment, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_boundary_match_key
-- Field: AgentDecisionRecords.BoundaryMatchKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_agent_decision_records_boundary_match_key(p_agent_decision_record_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT(calc_agent_decision_records_step_of_decision(p_agent_decision_record_id), '|', calc_agent_decision_records_deciding_agent_kind(p_agent_decision_record_id), '|', (SELECT NULLIF(decision_kind, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_matching_boundary_count
-- Field: AgentDecisionRecords.MatchingBoundaryCount
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_agent_decision_records_matching_boundary_count(p_agent_decision_record_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COUNT(*) FROM authority_boundaries WHERE calc_authority_boundaries_boundary_match_key(authority_boundary_id) = calc_agent_decision_records_boundary_match_key(p_agent_decision_record_id)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_violated_authority_boundary
-- Field: AgentDecisionRecords.ViolatedAuthorityBoundary
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_agent_decision_records_violated_authority_boundary(p_agent_decision_record_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_agent_decision_records_matching_boundary_count(p_agent_decision_record_id))::NUMERIC > 0)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_has_human_confirmation
-- Field: AgentDecisionRecords.HasHumanConfirmation
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_agent_decision_records_has_human_confirmation(p_agent_decision_record_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_agent_decision_records_reviewer_agent_kind(p_agent_decision_record_id) = 'Human' AND (SELECT NULLIF(human_disposition, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id) IS NOT NULL AND (SELECT NULLIF(human_disposition, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id) <> 'NotReviewed'))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_needs_human_confirmation
-- Field: AgentDecisionRecords.NeedsHumanConfirmation
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_agent_decision_records_needs_human_confirmation(p_agent_decision_record_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((NOT (calc_agent_decision_records_deciding_agent_kind(p_agent_decision_record_id) = 'Human') AND ((SELECT NULLIF(materiality_band, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id) = 'Material' OR (SELECT NULLIF(materiality_band, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id) = 'Escalated')))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_is_unconfirmed_non_human_decision
-- Field: AgentDecisionRecords.IsUnconfirmedNonHumanDecision
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_agent_decision_records_is_unconfirmed_non_human_decision(p_agent_decision_record_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_agent_decision_records_needs_human_confirmation(p_agent_decision_record_id) AND NOT (calc_agent_decision_records_has_human_confirmation(p_agent_decision_record_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_step_execution_when_unconfirmed
-- Field: AgentDecisionRecords.StepExecutionWhenUnconfirmed
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_agent_decision_records_step_execution_when_unconfirmed(p_agent_decision_record_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_agent_decision_records_is_unconfirmed_non_human_decision(p_agent_decision_record_id) THEN ((SELECT NULLIF(step_execution, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_agent_when_boundary_violated
-- Field: AgentDecisionRecords.AgentWhenBoundaryViolated
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_agent_decision_records_agent_when_boundary_violated(p_agent_decision_record_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_agent_decision_records_violated_authority_boundary(p_agent_decision_record_id) THEN ((SELECT NULLIF(deciding_agent, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_review_latency_minutes
-- Field: AgentDecisionRecords.ReviewLatencyMinutes
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_agent_decision_records_review_latency_minutes(p_agent_decision_record_id TEXT)
RETURNS INTEGER AS $$
  SELECT (CASE WHEN (SELECT reviewed_at::timestamptz FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id) IS NULL THEN (0)::text ELSE ((EXTRACT(EPOCH FROM ((SELECT reviewed_at::timestamptz FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id)::timestamp - (SELECT decided_at::timestamptz FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id)::timestamp)) / 60))::text END)::integer;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_is_draft_kind
-- Field: AgentDecisionRecords.IsDraftKind
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_agent_decision_records_is_draft_kind(p_agent_decision_record_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(decision_kind, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id) = 'Draft' OR (SELECT NULLIF(decision_kind, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id) = 'Commitment'))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_agent_when_draft_overridden
-- Field: AgentDecisionRecords.AgentWhenDraftOverridden
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_agent_decision_records_agent_when_draft_overridden(p_agent_decision_record_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (calc_agent_decision_records_is_draft_kind(p_agent_decision_record_id) AND calc_agent_decision_records_was_overridden(p_agent_decision_record_id)) THEN ((SELECT NULLIF(deciding_agent, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_agent_decision_records_agent_when_draft
-- Field: AgentDecisionRecords.AgentWhenDraft
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_agent_decision_records_agent_when_draft(p_agent_decision_record_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_agent_decision_records_is_draft_kind(p_agent_decision_record_id) THEN ((SELECT NULLIF(deciding_agent, '') FROM agent_decision_records WHERE agent_decision_record_id = p_agent_decision_record_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_delivered_communications_authorized_at
-- Field: DeliveredCommunications.AuthorizedAt
-- Type: lookup | DataType: datetime | Returns: TIMESTAMPTZ
-- Lookup: EndedAt from related StepExecutions


CREATE OR REPLACE FUNCTION calc_delivered_communications_authorized_at(p_delivered_communication_id TEXT)
RETURNS TIMESTAMPTZ AS $$
  SELECT (SELECT ended_at::timestamptz FROM step_executions WHERE step_execution_id = (SELECT authorizing_step_execution FROM delivered_communications WHERE delivered_communication_id = p_delivered_communication_id));
$$ LANGUAGE sql STABLE;

-- calc_delivered_communications_name
-- Field: DeliveredCommunications.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_delivered_communications_name(p_delivered_communication_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(channel, '') FROM delivered_communications WHERE delivered_communication_id = p_delivered_communication_id), ' -> ', (SELECT NULLIF(recipient_key, '') FROM delivered_communications WHERE delivered_communication_id = p_delivered_communication_id), ' @ ', (SELECT sent_at::timestamptz FROM delivered_communications WHERE delivered_communication_id = p_delivered_communication_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_delivered_communications_has_authorization
-- Field: DeliveredCommunications.HasAuthorization
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_delivered_communications_has_authorization(p_delivered_communication_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT NULLIF(authorizing_step_execution, '') FROM delivered_communications WHERE delivered_communication_id = p_delivered_communication_id) IS NOT NULL)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_delivered_communications_content_matches_approval
-- Field: DeliveredCommunications.ContentMatchesApproval
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_delivered_communications_content_matches_approval(p_delivered_communication_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT NULLIF(rendered_content_hash, '') FROM delivered_communications WHERE delivered_communication_id = p_delivered_communication_id) = (SELECT NULLIF(approved_content_hash, '') FROM delivered_communications WHERE delivered_communication_id = p_delivered_communication_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_delivered_communications_was_approved_before_sending
-- Field: DeliveredCommunications.WasApprovedBeforeSending
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_delivered_communications_was_approved_before_sending(p_delivered_communication_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_delivered_communications_authorized_at(p_delivered_communication_id) <= (SELECT sent_at::timestamptz FROM delivered_communications WHERE delivered_communication_id = p_delivered_communication_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_delivered_communications_is_defensible
-- Field: DeliveredCommunications.IsDefensible
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_delivered_communications_is_defensible(p_delivered_communication_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_delivered_communications_has_authorization(p_delivered_communication_id) AND calc_delivered_communications_content_matches_approval(p_delivered_communication_id) AND calc_delivered_communications_was_approved_before_sending(p_delivered_communication_id)))::boolean;
$$ LANGUAGE sql STABLE;

