-- calc_authority_boundaries_name
-- Field: AuthorityBoundaries.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_authority_boundaries_name(p_authority_boundary_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(forbidden_agent_kind, '') FROM authority_boundaries WHERE authority_boundary_id = p_authority_boundary_id), ' may not ', (SELECT NULLIF(forbidden_decision_kind, '') FROM authority_boundaries WHERE authority_boundary_id = p_authority_boundary_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_authority_boundaries_is_currently_binding
-- Field: AuthorityBoundaries.IsCurrentlyBinding
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_authority_boundaries_is_currently_binding(p_authority_boundary_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(status, '') FROM authority_boundaries WHERE authority_boundary_id = p_authority_boundary_id) = 'Approved' AND (SELECT valid_from::timestamptz FROM authority_boundaries WHERE authority_boundary_id = p_authority_boundary_id) <= calc_authority_boundaries_as_of_instant(p_authority_boundary_id) AND ((SELECT valid_to::timestamptz FROM authority_boundaries WHERE authority_boundary_id = p_authority_boundary_id) IS NULL OR (SELECT valid_to::timestamptz FROM authority_boundaries WHERE authority_boundary_id = p_authority_boundary_id) > calc_authority_boundaries_as_of_instant(p_authority_boundary_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_authority_boundaries_step_when_binding
-- Field: AuthorityBoundaries.StepWhenBinding
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_authority_boundaries_step_when_binding(p_authority_boundary_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_authority_boundaries_is_currently_binding(p_authority_boundary_id) THEN ((SELECT NULLIF(step, '') FROM authority_boundaries WHERE authority_boundary_id = p_authority_boundary_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_authority_boundaries_boundary_match_key
-- Field: AuthorityBoundaries.BoundaryMatchKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_authority_boundaries_boundary_match_key(p_authority_boundary_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(step, '') FROM authority_boundaries WHERE authority_boundary_id = p_authority_boundary_id), '|', (SELECT NULLIF(forbidden_agent_kind, '') FROM authority_boundaries WHERE authority_boundary_id = p_authority_boundary_id), '|', (SELECT NULLIF(forbidden_decision_kind, '') FROM authority_boundaries WHERE authority_boundary_id = p_authority_boundary_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_authority_boundaries_violation_count
-- Field: AuthorityBoundaries.ViolationCount
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_authority_boundaries_violation_count(p_authority_boundary_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COUNT(*) FROM agent_decision_records WHERE calc_agent_decision_records_boundary_match_key(agent_decision_record_id) = calc_authority_boundaries_boundary_match_key(p_authority_boundary_id)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_authority_boundaries_is_untested
-- Field: AuthorityBoundaries.IsUntested
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_authority_boundaries_is_untested(p_authority_boundary_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_authority_boundaries_is_currently_binding(p_authority_boundary_id) AND (calc_authority_boundaries_violation_count(p_authority_boundary_id))::NUMERIC = 0));
$$ LANGUAGE sql STABLE;

-- calc_authority_boundaries_has_ratifying_fragment
-- Field: AuthorityBoundaries.HasRatifyingFragment
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_authority_boundaries_has_ratifying_fragment(p_authority_boundary_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT NULLIF(ratified_by_knowledge_fragment, '') FROM authority_boundaries WHERE authority_boundary_id = p_authority_boundary_id) IS NOT NULL)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_authority_boundaries_is_unwarranted
-- Field: AuthorityBoundaries.IsUnwarranted
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_authority_boundaries_is_unwarranted(p_authority_boundary_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_authority_boundaries_is_currently_binding(p_authority_boundary_id) AND (NOT (calc_authority_boundaries_has_ratifying_fragment(p_authority_boundary_id)) OR NOT (calc_authority_boundaries_ratifying_fragment_is_valid(p_authority_boundary_id)))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_authority_boundaries_warrant_is_thin
-- Field: AuthorityBoundaries.WarrantIsThin
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_authority_boundaries_warrant_is_thin(p_authority_boundary_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_authority_boundaries_is_currently_binding(p_authority_boundary_id) AND (calc_authority_boundaries_ratifying_fragment_is_overdue(p_authority_boundary_id) OR calc_authority_boundaries_ratifying_fragment_is_single_witness(p_authority_boundary_id))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_authority_boundaries_is_unwarranted_and_untested
-- Field: AuthorityBoundaries.IsUnwarrantedAndUntested
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_authority_boundaries_is_unwarranted_and_untested(p_authority_boundary_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_authority_boundaries_is_unwarranted(p_authority_boundary_id) AND calc_authority_boundaries_is_untested(p_authority_boundary_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_authority_boundaries_unwarranted_boundary_step_key
-- Field: AuthorityBoundaries.UnwarrantedBoundaryStepKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_authority_boundaries_unwarranted_boundary_step_key(p_authority_boundary_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_authority_boundaries_is_unwarranted(p_authority_boundary_id) THEN ((SELECT NULLIF(step, '') FROM authority_boundaries WHERE authority_boundary_id = p_authority_boundary_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_authority_boundaries_ratifying_fragment_key
-- Field: AuthorityBoundaries.RatifyingFragmentKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_authority_boundaries_ratifying_fragment_key(p_authority_boundary_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_authority_boundaries_is_currently_binding(p_authority_boundary_id) THEN ((SELECT NULLIF(ratified_by_knowledge_fragment, '') FROM authority_boundaries WHERE authority_boundary_id = p_authority_boundary_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_binding_observations_sla_minutes_at_run
-- Field: BindingObservations.SlaMinutesAtRun
-- Type: lookup | DataType: integer | Returns: INTEGER
-- Lookup: FreshnessSlaMinutes from related OperationalBindings


CREATE OR REPLACE FUNCTION calc_binding_observations_sla_minutes_at_run(p_binding_observation_id TEXT)
RETURNS INTEGER AS $$
  SELECT (SELECT freshness_sla_minutes::integer FROM operational_bindings WHERE operational_binding_id = (SELECT operational_binding FROM binding_observations WHERE binding_observation_id = p_binding_observation_id));
$$ LANGUAGE sql STABLE;

-- calc_binding_observations_is_authoritative_binding
-- Field: BindingObservations.IsAuthoritativeBinding
-- Type: lookup | DataType: boolean | Returns: BOOLEAN
-- Lookup: IsAuthoritative from related OperationalBindings


CREATE OR REPLACE FUNCTION calc_binding_observations_is_authoritative_binding(p_binding_observation_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (SELECT is_authoritative::boolean FROM operational_bindings WHERE operational_binding_id = (SELECT operational_binding FROM binding_observations WHERE binding_observation_id = p_binding_observation_id));
$$ LANGUAGE sql STABLE;

-- calc_binding_observations_age_at_run_minutes
-- Field: BindingObservations.AgeAtRunMinutes
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_binding_observations_age_at_run_minutes(p_binding_observation_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((EXTRACT(EPOCH FROM ((SELECT read_at::timestamptz FROM binding_observations WHERE binding_observation_id = p_binding_observation_id)::timestamp - (SELECT observed_source_timestamp::timestamptz FROM binding_observations WHERE binding_observation_id = p_binding_observation_id)::timestamp)) / 60))::integer;
$$ LANGUAGE sql STABLE;

-- calc_binding_observations_was_stale_at_run
-- Field: BindingObservations.WasStaleAtRun
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_binding_observations_was_stale_at_run(p_binding_observation_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_binding_observations_is_authoritative_binding(p_binding_observation_id) AND calc_binding_observations_age_at_run_minutes(p_binding_observation_id) > calc_binding_observations_sla_minutes_at_run(p_binding_observation_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_binding_observations_stale_at_run_step_key
-- Field: BindingObservations.StaleAtRunStepKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_binding_observations_stale_at_run_step_key(p_binding_observation_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_binding_observations_was_stale_at_run(p_binding_observation_id) THEN ((SELECT NULLIF(step_execution, '') FROM binding_observations WHERE binding_observation_id = p_binding_observation_id))::text ELSE ('')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_attestations_version_is_fit_now
-- Field: Attestations.VersionIsFitNow
-- Type: lookup | DataType: boolean | Returns: BOOLEAN
-- Lookup: ExecutedVersionIsFit from related ProcedureExecutions


CREATE OR REPLACE FUNCTION calc_attestations_version_is_fit_now(p_attestation_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT calc_procedure_executions_executed_version_is_fit((SELECT procedure_execution FROM attestations WHERE attestation_id = p_attestation_id));
$$ LANGUAGE sql STABLE;

-- calc_attestations_assurance_grade_now
-- Field: Attestations.AssuranceGradeNow
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: AssuranceGrade from related ProcedureExecutions


CREATE OR REPLACE FUNCTION calc_attestations_assurance_grade_now(p_attestation_id TEXT)
RETURNS TEXT AS $$
  SELECT calc_procedure_executions_assurance_grade((SELECT procedure_execution FROM attestations WHERE attestation_id = p_attestation_id));
$$ LANGUAGE sql STABLE;

-- calc_attestations_fitness_verdict_has_drifted
-- Field: Attestations.FitnessVerdictHasDrifted
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_attestations_fitness_verdict_has_drifted(p_attestation_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (NOT ((SELECT version_was_fit_at_signing FROM attestations WHERE attestation_id = p_attestation_id) = calc_attestations_version_is_fit_now(p_attestation_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_attestations_assurance_grade_has_drifted
-- Field: Attestations.AssuranceGradeHasDrifted
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_attestations_assurance_grade_has_drifted(p_attestation_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (NOT ((SELECT NULLIF(assurance_grade_at_signing, '') FROM attestations WHERE attestation_id = p_attestation_id) = calc_attestations_assurance_grade_now(p_attestation_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_attestations_would_not_survive_restatement
-- Field: Attestations.WouldNotSurviveRestatement
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_attestations_would_not_survive_restatement(p_attestation_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_attestations_fitness_verdict_has_drifted(p_attestation_id) OR calc_attestations_assurance_grade_has_drifted(p_attestation_id)))::boolean;
$$ LANGUAGE sql STABLE;

